 30		"github.com/cloudwego/eino/components/prompt"
 31		"github.com/cloudwego/eino/compose"
 32		"github.com/cloudwego/eino/schema"
 33	
 34		commonModel "github.com/cloudwego/eino-examples/adk/common/model"
 35	)
 36	
 37	type rateLimitedModel struct {
 38		m     model.ToolCallingChatModel
 39		delay time.Duration
 40	}
 41	
 42	func (r *rateLimitedModel) WithTools(tools []*schema.ToolInfo) (model.ToolCallingChatModel, error) {
 43		newM, err := r.m.WithTools(tools)
 44		if err != nil {
 45			return nil, err
 46		}
 47		return &rateLimitedModel{newM, r.delay}, nil
 48	}
 49	
 50	func (r *rateLimitedModel) Generate(ctx context.Context, input []*schema.Message, opts ...model.Option) (*schema.Message, error) {
 51		time.Sleep(r.delay)
 52		return r.m.Generate(ctx, input, opts...)
 53	}
 54	
 55	func (r *rateLimitedModel) Stream(ctx context.Context, input []*schema.Message, opts ...model.Option) (*schema.StreamReader[*schema.Message], error) {
 56		time.Sleep(r.delay)
 57		return r.m.Stream(ctx, input, opts...)
 58	}
 59	
 60	func getRateLimitDelay() time.Duration {
 61		delayMs := os.Getenv("RATE_LIMIT_DELAY_MS")
 62		if delayMs == "" {
 63			return 0
 64		}
 65		ms, err := strconv.Atoi(delayMs)
 66		if err != nil {
 67			return 0
 68		}
 69		return time.Duration(ms) * time.Millisecond
 70	}
 71	
 72	func newRateLimitedModel() model.ToolCallingChatModel {
 73		delay := getRateLimitDelay()
 74		if delay == 0 {
 75			return commonModel.NewChatModel()
 76		}
 77		return &rateLimitedModel{
 78			m:     commonModel.NewChatModel(),
 79			delay: delay,
 80		}
 81	}
 82	
 83	func NewPlanner(ctx context.Context) (adk.Agent, error) {
 84		return planexecute.NewPlanner(ctx, &planexecute.PlannerConfig{
 85			ToolCallingChatModel: newRateLimitedModel(),
 86		})
 87	}
 88	
 89	var executorPrompt = prompt.FromMessages(schema.FString,
 90		schema.SystemMessage(`You are a diligent travel booking assistant. Follow the given plan and execute your tasks carefully.
 91	Execute each planning step by using available tools.
 92	For weather queries, use get_weather tool.
 93	For flight bookings, use book_flight tool - this will require user review before confirmation.
 94	For hotel bookings, use book_hotel tool - this will require user review before confirmation.
 95	For attraction research, use search_attractions tool.
 96	Provide detailed results for each task.`),
 97		schema.UserMessage(`## OBJECTIVE
 98	{input}
 99	## Given the following plan:
100	{plan}
101	## COMPLETED STEPS & RESULTS
102	{executed_steps}
103	## Your task is to execute the first step, which is: 
104	{step}`))
105	
106	func formatInput(in []adk.Message) string {
107		return in[0].Content
108	}
109	
110	func formatExecutedSteps(in []planexecute.ExecutedStep) string {
111		var sb strings.Builder
112		for idx, m := range in {
113			_, _ = fmt.Fprintf(&sb, "## %d. Step: %v\n  Result: %v\n\n", idx+1, m.Step, m.Result)
114		}
115		return sb.String()
116	}
117	
118	func NewExecutor(ctx context.Context) (adk.Agent, error) {
119		travelTools, err := GetAllTravelTools(ctx)
120		if err != nil {
121			return nil, err
122		}
123	
124		return planexecute.NewExecutor(ctx, &planexecute.ExecutorConfig{
125			Model: newRateLimitedModel(),
126			ToolsConfig: adk.ToolsConfig{
127				ToolsNodeConfig: compose.ToolsNodeConfig{
128					Tools: travelTools,
129				},
130			},
131	
132			GenInputFn: func(ctx context.Context, in *planexecute.ExecutionContext) ([]adk.Message, error) {
133				planContent, err_ := in.Plan.MarshalJSON()
134				if err_ != nil {
135					return nil, err_
136				}
137	
138				firstStep := in.Plan.FirstStep()
139	
140				msgs, err_ := executorPrompt.Format(ctx, map[string]any{
141					"input":          formatInput(in.UserInput),
142					"plan":           string(planContent),
143					"executed_steps": formatExecutedSteps(in.ExecutedSteps),
144					"step":           firstStep,
145				})
146				if err_ != nil {
147					return nil, err_
148				}
149	
150				return msgs, nil
151			},
152		})
153	}
154	
155	func NewReplanner(ctx context.Context) (adk.Agent, error) {
156		return planexecute.NewReplanner(ctx, &planexecute.ReplannerConfig{
157			ChatModel: newRateLimitedModel(),
158		})
159	}
160	
161	func NewTravelPlanningAgent(ctx context.Context) (adk.Agent, error) {
162		planAgent, err := NewPlanner(ctx)
163		if err != nil {
164			return nil, err
165		}
166	
167		executeAgent, err := NewExecutor(ctx)
168		if err != nil {
169			return nil, err
170		}
171	
172		replanAgent, err := NewReplanner(ctx)
173		if err != nil {
174			return nil, err
175		}
176	
177		return planexecute.New(ctx, &planexecute.Config{
178			Planner:       planAgent,
179			Executor:      executeAgent,
180			Replanner:     replanAgent,
181			MaxIterations: 20,
182		})
183	}

