 36		PlannerModel        model.BaseChatModel // planner 智能体使用的大模型
 37		PlannerSystemPrompt string              // planner 智能体的 system prompt
 38	
 39		ExecutorModel        model.ToolCallingChatModel // executor 智能体使用的大模型
 40		ToolsConfig          compose.ToolsNodeConfig    // executor 智能体使用的工具执行器配置
 41		ExecutorSystemPrompt string                     // executor 智能体的 system prompt
 42	
 43		ReviserModel        model.BaseChatModel // reviser 智能体使用的大模型
 44		ReviserSystemPrompt string              // reviser 智能体的 system prompt
 45	
 46		MaxStep int // 多智能体的最大执行步骤数，避免无限循环
 47	}
