 49	// PlanExecuteMultiAgent “计划——执行”多智能体.
 50	type PlanExecuteMultiAgent struct {
 51		// 图编排后的可执行体，输入是 Message 数组，输出是单条 Message
 52		runnable compose.Runnable[[]*schema.Message, *schema.Message]
 53	}
 54	
 55	// state 以多智能体一次运行为 scope 的全局状态，用于记录上下文
 56	type state struct {
 57		messages []*schema.Message
 58	}
 59	
 60	const (
 61		nodeKeyPlanner        = "planner"          // planner 智能体的节点 key
 62		nodeKeyExecutor       = "executor"         // executor 智能体的节点 key
 63		nodeKeyReviser        = "reviser"          // reviser 智能体的节点 key
 64		nodeKeyTools          = "tools"            // tools 执行器的节点 key
 65		nodeKeyPlannerToList  = "planner_to_list"  // planner->executor 之间的 converter 节点 key
 66		nodeKeyExecutorToList = "executor_to_list" // executor->reviser 之间的 converter 节点 key
 67		nodeKeyReviserToList  = "reviser_to_list"  // reviser->executor 之间的 converter 节点 key
 68		defaultMaxStep        = 100                // 默认的最大执行步骤数量
 69	)
