 71	// NewMultiAgent 根据配置编排一个“计划——执行”多智能体.
 72	func NewMultiAgent(ctx context.Context, config *Config) (*PlanExecuteMultiAgent, error) {
 73		var (
 74			toolInfos      []*schema.ToolInfo
 75			toolsNode      *compose.ToolsNode
 76			err            error
 77			plannerPrompt  = config.PlannerSystemPrompt
 78			executorPrompt = config.ExecutorSystemPrompt
 79			reviserPrompt  = config.ReviserSystemPrompt
 80			maxStep        = config.MaxStep
 81		)
 82	
 83		if len(plannerPrompt) == 0 {
 84			plannerPrompt = prompt.DefaultPlannerPrompt
 85		}
 86	
 87		if len(executorPrompt) == 0 {
 88			executorPrompt = prompt.DefaultExecutorPrompt
 89		}
 90	
 91		if len(reviserPrompt) == 0 {
 92			reviserPrompt = prompt.DefaultReviserPrompt
 93		}
 94	
 95		if maxStep == 0 {
 96			maxStep = defaultMaxStep
 97		}
 98	
 99		if toolInfos, err = genToolInfos(ctx, config.ToolsConfig); err != nil {
100			return nil, err
101		}
102	
103		// 为 Executor 配置工具
104		if config.ExecutorModel, err = config.ExecutorModel.WithTools(toolInfos); err != nil {
105			return nil, err
106		}
107	
108		// 初始化 Tool 执行器节点，传入可执行的工具
109		if toolsNode, err = compose.NewToolNode(ctx, &config.ToolsConfig); err != nil {
110			return nil, err
111		}
112	
113		// 创建一个待编排的 graph，规定整体的输入输出类型，配置全局状态的初始化方法
114		graph := compose.NewGraph[[]*schema.Message, *schema.Message](compose.WithGenLocalState(func(ctx context.Context) *state {
115			return &state{}
116		}))
117	
118		// 在大模型执行之前，向全局状态中保存上下文，并组装本次的上下文
119		modelPreHandle := func(systemPrompt string, isDeepSeek bool) compose.StatePreHandler[[]*schema.Message, *state] {
120			return func(ctx context.Context, input []*schema.Message, state *state) ([]*schema.Message, error) {
121				state.messages = append(state.messages, input...)
122	
123				if isDeepSeek {
124					return append([]*schema.Message{schema.SystemMessage(systemPrompt)}, convertMessagesForDeepSeek(state.messages)...), nil
125				}
126	
127				return append([]*schema.Message{schema.SystemMessage(systemPrompt)}, convertMessagesForArk(state.messages)...), nil
128			}
129		}
130	
131		// 定义 Executor 后的分支判断用的条件函数。该函数的输出是运行时选中的 NodeKey
132		executorPostBranchCondition := func(_ context.Context, msg *schema.Message) (endNode string, err error) {
133			if len(msg.ToolCalls) == 0 {
134				return nodeKeyExecutorToList, nil
135			}
136	
137			return nodeKeyTools, nil
138		}
139	
140		// 定义 Reviser 后的分支判断用的条件函数。
141		reviserPostBranchCondition := func(_ context.Context, sr *schema.StreamReader[*schema.Message]) (endNode string, err error) {
142			defer sr.Close()
143	
144			var content string
145			for {
146				msg, err := sr.Recv()
147				if err != nil {
148					if err == io.EOF {
149						return nodeKeyReviserToList, nil
150					}
151					return "", err
152				}
153	
154				content += msg.Content
155	
156				if strings.Contains(content, "最终答案") {
157					return compose.END, nil
158				}
159			}
160		}
161	
162		// 添加 Planner 节点，同时添加 StatePreHandler 读写上下文
163		_ = graph.AddChatModelNode(nodeKeyPlanner, config.PlannerModel, compose.WithStatePreHandler(modelPreHandle(plannerPrompt, true)), compose.WithNodeName(nodeKeyPlanner))
164	
165		// 添加 Executor 节点，同时添加 StatePreHandler 读写上下文
166		_ = graph.AddChatModelNode(nodeKeyExecutor, config.ExecutorModel, compose.WithStatePreHandler(modelPreHandle(executorPrompt, false)), compose.WithNodeName(nodeKeyExecutor))
167	
168		// 添加 Reviser 节点，同时添加 StatePreHandler 读写上下文
169		_ = graph.AddChatModelNode(nodeKeyReviser, config.ReviserModel, compose.WithStatePreHandler(modelPreHandle(reviserPrompt, true)), compose.WithNodeName(nodeKeyReviser))
170	
171		// 添加 Tool 执行器节点，同时添加 StatePreHandler 读写上下文
172		_ = graph.AddToolsNode(nodeKeyTools, toolsNode, compose.WithStatePreHandler(func(ctx context.Context, in *schema.Message, state *state) (*schema.Message, error) {
173			state.messages = append(state.messages, in)
174			return in, nil
175		}))
176	
177		// 添加三个 ToList 转换节点
178		_ = graph.AddLambdaNode(nodeKeyPlannerToList, compose.ToList[*schema.Message]())
179		_ = graph.AddLambdaNode(nodeKeyExecutorToList, compose.ToList[*schema.Message]())
180		_ = graph.AddLambdaNode(nodeKeyReviserToList, compose.ToList[*schema.Message]())
181	
182		// 添加节点之间的边和分支
183		_ = graph.AddEdge(compose.START, nodeKeyPlanner)
184		_ = graph.AddEdge(nodeKeyPlanner, nodeKeyPlannerToList)
185		_ = graph.AddEdge(nodeKeyPlannerToList, nodeKeyExecutor)
186		_ = graph.AddBranch(nodeKeyExecutor, compose.NewGraphBranch(executorPostBranchCondition, map[string]bool{
187			nodeKeyTools:          true,
188			nodeKeyExecutorToList: true,
189		}))
190		_ = graph.AddEdge(nodeKeyTools, nodeKeyExecutor)
191		_ = graph.AddEdge(nodeKeyExecutorToList, nodeKeyReviser)
192		_ = graph.AddBranch(nodeKeyReviser, compose.NewStreamGraphBranch(reviserPostBranchCondition, map[string]bool{
193			nodeKeyReviserToList: true,
194			compose.END:          true,
195		}))
196		_ = graph.AddEdge(nodeKeyReviserToList, nodeKeyExecutor)
197	
198		// 编译 graph，并生成 Mermaid 拓扑图。由于 graph 中存在环，使用 AnyPredecessor 模式，同时设置运行时最大步数。
199		gen := visualize.NewMermaidGenerator("flow/agent/multiagent/plan_execute")
200		runnable, err := graph.Compile(ctx,
201			compose.WithNodeTriggerMode(compose.AnyPredecessor),
202			compose.WithMaxRunSteps(maxStep),
203			compose.WithGraphCompileCallbacks(gen),
204			compose.WithGraphName("PlanExecuteMultiAgent"),
205		)
206		if err != nil {
207			return nil, err
208		}
209	
210		// Mermaid markdown and images are auto-generated in flow/agent/multiagent/plan_execute
211	
212		return &PlanExecuteMultiAgent{
213			runnable: runnable,
214		}, nil
215	}
