239	// 把可执行的 Tool 转化为大模型可用的 Tool 信息
240	func genToolInfos(ctx context.Context, config compose.ToolsNodeConfig) ([]*schema.ToolInfo, error) {
241		toolInfos := make([]*schema.ToolInfo, 0, len(config.Tools))
242		for _, t := range config.Tools {
243			tl, err := t.Info(ctx)
244			if err != nil {
245				return nil, err
246			}
247	
248			toolInfos = append(toolInfos, tl)
249		}
250	
251		return toolInfos, nil
252	}
