254	func convertMessagesForDeepSeek(messages []*schema.Message) (converted []*schema.Message) {
255		converted = make([]*schema.Message, 0, len(messages)*2)
256		for _, message := range messages {
257			switch message.Role {
258			case schema.Tool: // 有 DeepSeek 服务商如火山引擎，目前不支持传入 ToolMessage
259				converted = append(converted, schema.AssistantMessage(message.Content, nil))
260			case schema.Assistant:
261				if len(message.ToolCalls) == 0 {
262					if len(message.Content) > 0 {
263						converted = append(converted, message)
264					}
265				} else {
266					if len(message.Content) > 0 {
267						converted = append(converted, schema.AssistantMessage(message.Content, nil))
268					}
269					for _, toolCall := range message.ToolCalls {
270						converted = append(converted, schema.AssistantMessage(fmt.Sprintf("call %s with %s, got response:", toolCall.Function.Name, toolCall.Function.Arguments), nil))
271					}
272				}
273			default:
274				converted = append(converted, message)
275			}
276		}
277	
278		return converted
279	}
280	
281	func convertMessagesForArk(messages []*schema.Message) (converted []*schema.Message) {
282		converted = make([]*schema.Message, 0, len(messages)*2)
283		for _, message := range messages {
284			if message.Role == schema.Assistant {
285				if len(message.ToolCalls) == 0 {
286					if len(message.Content) > 0 {
287						converted = append(converted, message)
288					}
289				} else {
290					converted = append(converted, message)
291				}
292			} else {
293				converted = append(converted, message)
294			}
295		}
296	
297		return converted
298	}

