125	type coloredString struct {
126		str  string
127		code string
128	}
129	
130	// intermediateOutputPrinter 利用 Eino 的 callback 机制，收集多智能体各步骤的实时输出.
131	type intermediateOutputPrinter struct {
132		ch               chan coloredString
133		currentAgentName string          // 当前智能体名称
134		agentReasoning   map[string]bool // 智能体处在“推理”阶段还是“最终答案”阶段
135		mu               sync.Mutex
136		wg               sync.WaitGroup
137	}
138	
139	func newIntermediateOutputPrinter() *intermediateOutputPrinter {
140		return &intermediateOutputPrinter{
141			ch: make(chan coloredString),
142			agentReasoning: map[string]bool{
143				nodeKeyPlanner:  false,
144				nodeKeyExecutor: false,
145				nodeKeyReviser:  false,
146			},
147		}
148	}
149	
150	func (s *intermediateOutputPrinter) printStream() {
151		go func() {
152			for m := range s.ch {
153				fmt.Print(m.code + m.str + Reset)
154			}
155		}()
156	}
157	
158	func (s *intermediateOutputPrinter) toCallbackHandler() callbacks2.Handler {
159		return callbacks.NewHandlerHelper().ChatModel(&callbacks.ModelCallbackHandler{
160			OnEndWithStreamOutput: s.onChatModelEndWithStreamOutput,
161		}).Tool(&callbacks.ToolCallbackHandler{
162			OnStart: s.onToolStart,
163			OnEnd:   s.onToolEnd,
164		}).Handler()
165	}
166	
167	func (s *intermediateOutputPrinter) wait() {
168		s.wg.Wait()
169	}
170	
171	const (
172		Reset  = "\033[0m"
173		Red    = "\033[31m"
174		Green  = "\033[32m"
175		Yellow = "\033[33m"
176		Blue   = "\033[34m"
177		White  = "\033[97m"
178		Cyan   = "\033[36m"
179		Gray   = "\033[37m"
180	)
181	
182	// onChatModelEndWithStreamOutput 当 ChatModel 结束时，获取它的流式输出并格式化处理.
183	func (s *intermediateOutputPrinter) onChatModelEndWithStreamOutput(ctx context.Context, runInfo *callbacks2.RunInfo, output *schema.StreamReader[*model.CallbackOutput]) context.Context {
184		name := runInfo.Name
185		if name != s.currentAgentName {
186			s.ch <- coloredString{fmt.Sprintf("\n\n=======\n%s: \n=======\n", name), Cyan}
187			s.currentAgentName = name
188		}
189	
190		s.wg.Add(1)
191	
192		go func() {
193			defer output.Close()
194			defer s.wg.Done()
195	
196			for {
197				chunk, err := output.Recv()
198				if err != nil {
199					if errors.Is(err, io.EOF) {
200						break
201					}
202					log.Fatalf("internal error: %s\n", err)
203				}
204	
205				if len(chunk.Message.Content) > 0 {
206					if s.agentReasoning[name] { // 切换到最终答案阶段
207						s.ch <- coloredString{"\nanswer begin: \n", Green}
208						s.mu.Lock()
209						s.agentReasoning[name] = false
210						s.mu.Unlock()
211					}
212					s.ch <- coloredString{chunk.Message.Content, Yellow}
213				} else if reasoningContent, ok := deepseek.GetReasoningContent(chunk.Message); ok {
214					if !s.agentReasoning[name] { // 切换到推理阶段
215						s.ch <- coloredString{"\nreasoning begin: \n", Green}
216						s.mu.Lock()
217						s.agentReasoning[name] = true
218						s.mu.Unlock()
219					}
220					s.ch <- coloredString{reasoningContent, White}
221				}
222			}
223		}()
224	
225		return ctx
226	}
