228	// onToolStart 当 Tool 执行开始时，获取并输出调用信息.
229	func (s *intermediateOutputPrinter) onToolStart(ctx context.Context, info *callbacks2.RunInfo, input *tool.CallbackInput) context.Context {
230		arguments := make(map[string]any)
231		err := sonic.Unmarshal([]byte(input.ArgumentsInJSON), &arguments)
232		if err != nil {
233			s.ch <- coloredString{fmt.Sprintf("\ncall %s: %s\n", info.Name, input.ArgumentsInJSON), Red}
234			return ctx
235		}
236	
237		formatted, err := sonic.MarshalIndent(arguments, "  ", "  ")
238		if err != nil {
239			s.ch <- coloredString{fmt.Sprintf("\ncall %s: %s\n", info.Name, input.ArgumentsInJSON), Red}
240			return ctx
241		}
242	
243		s.ch <- coloredString{fmt.Sprintf("\ncall %s: %s\n", info.Name, string(formatted)), Red}
244		return ctx
245	}
246	
247	// onToolEnd 当 Tool 执行结束时，获取并输出返回结果.
248	func (s *intermediateOutputPrinter) onToolEnd(ctx context.Context, info *callbacks2.RunInfo, output *tool.CallbackOutput) context.Context {
249		response := make(map[string]any)
250		err := sonic.Unmarshal([]byte(output.Response), &response)
251		if err != nil {
252			s.ch <- coloredString{fmt.Sprintf("\ncall %s: %s\n", info.Name, output.Response), Blue}
253			return ctx
254		}
255	
256		formatted, err := sonic.MarshalIndent(response, "  ", "  ")
257		if err != nil {
258			s.ch <- coloredString{fmt.Sprintf("\ncall %s: %s\n", info.Name, output.Response), Blue}
259			return ctx
260		}
261	
262		s.ch <- coloredString{fmt.Sprintf("\ncall %s result: %s\n", info.Name, string(formatted)), Blue}
263		return ctx
264	}

