 32	func buildSearchAgent(ctx context.Context) (adk.Agent, error) {
 33		m := model.NewChatModel()
 34	
 35		type searchReq struct {
 36			Query string `json:"query"`
 37		}
 38	
 39		type searchResp struct {
 40			Result string `json:"result"`
 41		}
 42	
 43		search := func(ctx context.Context, req *searchReq) (*searchResp, error) {
 44			return &searchResp{
 45				Result: "In 2024, the US GDP was $29.18 trillion and New York State's GDP was $2.297 trillion",
 46			}, nil
 47		}
 48	
 49		searchTool, err := tools.SafeInferTool("search", "search the internet for info", search)
 50		if err != nil {
 51			return nil, err
 52		}
 53	
 54		return adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
 55			Name:        "research_agent",
 56			Description: "the agent responsible to search the internet for info",
 57			Instruction: `
 58			You are a research agent.
 59	
 60	
 61	        INSTRUCTIONS:
 62	        - Assist ONLY with research-related tasks, DO NOT do any math
 63	        - DO NOT estimate any numbers.
 64	        - After you're done with your tasks, respond to the supervisor directly
 65	        - Respond ONLY with the results of your work, do NOT include ANY other text.`,
 66			Model: m,
 67			ToolsConfig: adk.ToolsConfig{
 68				ToolsNodeConfig: compose.ToolsNodeConfig{
 69					Tools: []tool.BaseTool{searchTool},
 70					UnknownToolsHandler: func(ctx context.Context, name, input string) (string, error) {
 71						return fmt.Sprintf("unknown tool: %s", name), nil
 72					},
 73				},
 74			},
 75		})
 76	}
