 78	func buildMathAgent(ctx context.Context) (adk.Agent, error) {
 79		m := model.NewChatModel()
 80	
 81		type addReq struct {
 82			A float64 `json:"a"`
 83			B float64 `json:"b"`
 84		}
 85	
 86		type addResp struct {
 87			Result float64
 88		}
 89	
 90		add := func(ctx context.Context, req *addReq) (*addResp, error) {
 91			return &addResp{
 92				Result: req.A + req.B,
 93			}, nil
 94		}
 95	
 96		addTool, err := tools.SafeInferTool("add", "add two numbers", add)
 97		if err != nil {
 98			return nil, err
 99		}
100	
101		type multiplyReq struct {
102			A float64 `json:"a"`
103			B float64 `json:"b"`
104		}
105	
106		type multiplyResp struct {
107			Result float64
108		}
109	
110		multiply := func(ctx context.Context, req *multiplyReq) (*multiplyResp, error) {
111			return &multiplyResp{
112				Result: req.A * req.B,
113			}, nil
114		}
115	
116		multiplyTool, err := tools.SafeInferTool("multiply", "multiply two numbers", multiply)
117		if err != nil {
118			return nil, err
119		}
120	
121		type divideReq struct {
122			A float64 `json:"a"`
123			B float64 `json:"b"`
124		}
125	
126		type divideResp struct {
127			Result float64
128		}
129	
130		divide := func(ctx context.Context, req *divideReq) (*divideResp, error) {
131			return &divideResp{
132				Result: req.A / req.B,
133			}, nil
134		}
135	
136		divideTool, err := tools.SafeInferTool("divide", "divide two numbers", divide)
137		if err != nil {
138			return nil, err
139		}
140		return adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
141			Name:        "math_agent",
142			Description: "the agent responsible to do math",
143			Instruction: `
144			You are a math agent.
145	
146	
147	        INSTRUCTIONS:
148	        - Assist ONLY with math-related tasks
149	        - After you're done with your tasks, respond to the supervisor directly
150	        - Respond ONLY with the results of your work, do NOT include ANY other text.`,
151			Model: m,
152			ToolsConfig: adk.ToolsConfig{
153				ToolsNodeConfig: compose.ToolsNodeConfig{
154					Tools: []tool.BaseTool{addTool, multiplyTool, divideTool},
155					UnknownToolsHandler: func(ctx context.Context, name, input string) (string, error) {
156						return fmt.Sprintf("unknown tool: %s", name), nil
157					},
158				},
159			},
160		})
161	}
