 74	func main() {
 75		ctx := context.Background()
 76	
 77		// init tools
 78		sb := newSandbox(ctx)
 79		defer sb.Cleanup(ctx)
 80		commandlineTools := newCommandLineTools(ctx, sb)
 81		browserTool := newBrowserTool(ctx)
 82		defer browserTool.Cleanup()
 83	
 84		// init chat model
 85		cm := newChatModel(ctx)
 86		cm = bindTools(ctx, cm, append(commandlineTools, browserTool))
 87	
 88		// init and register callback handlers for logging and tracing
 89		var handlers []callbacks.Handler
 90		if len(langfuseHost) > 0 {
 91			langfuseHandler, flusher := newLangfuseHandler()
 92			handlers = append(handlers, langfuseHandler)
 93			defer flusher()
 94		}
 95		if cozeloopApiToken != "" && cozeloopWorkspaceID != "" {
 96			client, err := cozeloop.NewClient(
 97				cozeloop.WithAPIToken(cozeloopApiToken),
 98				cozeloop.WithWorkspaceID(cozeloopWorkspaceID),
 99			)
100			if err != nil {
101				panic(err)
102			}
103			defer client.Close(ctx)
104			handlers = append(handlers, clc.NewLoopHandler(client))
105		}
106		handlers = append(handlers, newLogHandler())
107		callbacks.AppendGlobalHandlers(handlers...)
108	
109		// compose graph
110		agent := composeAgent(ctx, cm, browserTool, commandlineTools)
111	
112		// init langfuse trace
113		ctx = langfuse.SetTrace(ctx, langfuse.WithID(uuid.New().String()))
114	
115		var userInput string
116		for {
117			result, err := agent.Invoke(ctx, input,
118				compose.WithCheckPointID("1"),
119				compose.WithStateModifier(func(ctx context.Context, path compose.NodePath, s any) error {
120					s.(*state).UserInput = userInput
121					return nil
122				}),
123				compose.WithRuntimeMaxSteps(20),
124			)
125			info, ok := compose.ExtractInterruptInfo(err)
126			if ok {
127				s := info.State.(*state)
128				fmt.Printf("ChatModel Output: %s\n", s.History[len(s.History)-1].Content)
129				fmt.Print("Do you want to continue? (y/n): ")
130				reader := bufio.NewReader(os.Stdin)
131				response, _ := reader.ReadString('\n')
132				response = strings.TrimSpace(response)
133	
134				if strings.ToLower(response) == "y" {
135					fmt.Print("Please enter your query: ")
136					userInput, _ = reader.ReadString('\n')
137					userInput = strings.TrimSpace(userInput)
138				} else {
139					userInput = ""
140				}
141				continue
142			}
143			if err != nil {
144				log.Printf("agent run error: %v", err)
145				return
146			}
147			fmt.Printf("[FinalResult]: %s", result)
148			break
149		}
150	}
