330	func appendNextPrompt(ctx context.Context, browserTool *browseruse.Tool) func(ctx context.Context, toolsNodeOutput []*schema.Message, state *state) ([]*schema.Message, error) {
331		info, err := browserTool.Info(ctx)
332		if err != nil {
333			log.Fatal("get browser tool info fail: ", err)
334		}
335		return func(ctx context.Context, toolsNodeOutput []*schema.Message, state *state) ([]*schema.Message, error) {
336			// append next prompt step prompt
337			// if call browser tool -> get browser state and append
338			// else append common prompt
339			if len(state.History) == 0 {
340				return toolsNodeOutput, nil
341			}
342	
343			llmToolCallMessage := state.History[len(state.History)-1]
344			for _, tc := range llmToolCallMessage.ToolCalls {
345				if tc.Function.Name == info.Name {
346					bState, err := browserTool.GetCurrentState()
347					if err != nil {
348						return nil, fmt.Errorf("failed to get browser tool state: %w", err)
349					}
350					bPrompt, err := formatBrowserToolPrompt(ctx, bState)
351					if err != nil {
352						return nil, fmt.Errorf("failed to format browser tool prompt: %w", err)
353					}
354					return append(toolsNodeOutput, bPrompt), nil
355				}
356			}
357	
358			return append(toolsNodeOutput, schema.UserMessage(nextStepPrompt)), nil
359		}
360	}
361	
362	func formatBrowserToolPrompt(ctx context.Context, bs *browseruse.BrowserState) (*schema.Message, error) {
363		if bs == nil {
364			return nil, fmt.Errorf("browser state is nil")
365		}
366		messages, err := schema.UserMessage(browserNextStepPrompt).Format(ctx, map[string]any{
367			"url_placeholder":           bs.URL,
368			"tabs_placeholder":          fmt.Sprintf("%+v", bs.Tabs),
369			"content_above_placeholder": bs.ScrollInfo.PixelsAbove,
370			"content_below_placeholder": bs.ScrollInfo.PixelsBelow,
371			"results_placeholder":       "",
372		}, schema.FString)
373		if err != nil {
374			return nil, err
375		}
376		message := messages[0]
377		if len(bs.Screenshot) > 0 {
378			message = schema.UserMessage("")
379			message.MultiContent = append(message.MultiContent,
380				schema.ChatMessagePart{
381					Type: schema.ChatMessagePartTypeText,
382					Text: messages[0].Content,
383				},
384				schema.ChatMessagePart{
385					Type: schema.ChatMessagePartTypeText,
386					Text: "Current browser screenshot:",
387				},
388				schema.ChatMessagePart{
389					Type: schema.ChatMessagePartTypeImageURL,
390					ImageURL: &schema.ChatMessageImageURL{
391						URL: "data:image/png;base64," + bs.Screenshot,
392					},
393				})
394		}
395		return message, nil
396	}
