313	func bindTools(ctx context.Context, cm model.ToolCallingChatModel, tools []tool.BaseTool) model.ToolCallingChatModel {
314		infos := make([]*schema.ToolInfo, 0, len(tools))
315		for _, t := range tools {
316			info, err := t.Info(ctx)
317			if err != nil {
318				log.Fatal("get tool info of fail: ", err)
319			}
320			infos = append(infos, info)
321		}
322	
323		ncm, err := cm.WithTools(infos)
324		if err != nil {
325			log.Fatal("bind tools fail: ", err)
326		}
327		return ncm
328	}
