163	func buildSupervisor(ctx context.Context) (adk.Agent, error) {
164		m := model.NewChatModel()
165	
166		sv, err := adk.NewChatModelAgent(ctx, &adk.ChatModelAgentConfig{
167			Name:        "supervisor",
168			Description: "the agent responsible to supervise tasks",
169			Instruction: `
170			You are a supervisor managing two agents:
171	
172	        - a research agent. Assign research-related tasks to this agent
173	        - a math agent. Assign math-related tasks to this agent
174	        Assign work to one agent at a time, do not call agents in parallel.
175	        Do not do any work yourself.`,
176			Model: m,
177			Exit:  &adk.ExitTool{},
178		})
179		if err != nil {
180			return nil, err
181		}
182	
183		searchAgent, err := buildSearchAgent(ctx)
184		if err != nil {
185			return nil, err
186		}
187		mathAgent, err := buildMathAgent(ctx)
188		if err != nil {
189			return nil, err
190		}
191	
192		return supervisor.New(ctx, &supervisor.Config{
193			Supervisor: sv,
194			SubAgents:  []adk.Agent{searchAgent, mathAgent},
195		})
196	}

