152	type state struct {
153		History   []*schema.Message
154		UserInput string
155	}
156	
157	const (
158		NodeKeyInputConvert  = "InputConverter"
159		NodeKeyChatModel     = "ChatModel"
160		NodeKeyToolsNode     = "ToolsNode"
161		NodeKeyHuman         = "Human"
162		NodeKeyOutputConvert = "OutputConverter"
163	)
164	
165	func composeAgent(ctx context.Context,
166		cm model.BaseChatModel,
167		browserTool *browseruse.Tool,
168		tools []tool.BaseTool,
169	) compose.Runnable[string, string] {
170		err := compose.RegisterSerializableType[state]("my state")
171		if err != nil {
172			log.Fatal(err)
173		}
174		err = compose.RegisterSerializableType[schema.ChatMessagePartType]("cmpt")
175		if err != nil {
176			log.Fatal(err)
177		}
178		err = compose.RegisterSerializableType[schema.ChatMessageImageURL]("cmiu")
179		if err != nil {
180			log.Fatal(err)
181		}
182		err = compose.RegisterSerializableType[schema.ChatMessageAudioURL]("cnau")
183		if err != nil {
184			log.Fatal(err)
185		}
186		err = compose.RegisterSerializableType[schema.ChatMessageVideoURL]("cmvu")
187		if err != nil {
188			log.Fatal(err)
189		}
190		err = compose.RegisterSerializableType[schema.ChatMessageFileURL]("cmfu")
191		if err != nil {
192			log.Fatal(err)
193		}
194		err = compose.RegisterSerializableType[schema.ImageURLDetail]("iud")
195		if err != nil {
196			log.Fatal(err)
197		}
198	
199		g := compose.NewGraph[string, string](compose.WithGenLocalState(func(ctx context.Context) *state {
200			return &state{History: []*schema.Message{}}
201		}))
202	
203		// register nodes
204		err = g.AddLambdaNode(NodeKeyInputConvert, compose.InvokableLambda(func(ctx context.Context, input string) (output []*schema.Message, err error) {
205			return []*schema.Message{
206				schema.SystemMessage(systemPrompt),
207				schema.UserMessage(input),
208			}, nil
209		}), compose.WithNodeName(NodeKeyInputConvert))
210		if err != nil {
211			log.Fatal(err)
212		}
213	
214		err = g.AddChatModelNode(
215			NodeKeyChatModel,
216			cm,
217			compose.WithNodeName(NodeKeyChatModel),
218			// append other node's output to History and load History to llm input
219			compose.WithStatePreHandler(func(ctx context.Context, in []*schema.Message, state *state) ([]*schema.Message, error) {
220				state.History = append(state.History, in...)
221				return state.History, nil
222			}),
223			compose.WithStatePostHandler(func(ctx context.Context, out *schema.Message, state *state) (*schema.Message, error) {
224				state.History = append(state.History, out)
225				return out, nil
226			}),
227		)
228		if err != nil {
229			log.Fatal(err)
230		}
231	
232		toolsNode, err := compose.NewToolNode(ctx, &compose.ToolsNodeConfig{Tools: append(tools, browserTool)})
233		if err != nil {
234			log.Fatal(err)
235		}
236		err = g.AddToolsNode(
237			NodeKeyToolsNode,
238			toolsNode,
239			compose.WithNodeName(NodeKeyToolsNode),
240			compose.WithStatePostHandler(appendNextPrompt(ctx, browserTool)),
241		)
242		if err != nil {
243			log.Fatal(err)
244		}
245	
246		err = g.AddLambdaNode(NodeKeyHuman, compose.InvokableLambda(func(ctx context.Context, input *schema.Message) (output []*schema.Message, err error) {
247			return []*schema.Message{input}, nil
248		}), compose.WithNodeName(NodeKeyHuman),
249			compose.WithStatePostHandler(func(ctx context.Context, in []*schema.Message, state *state) ([]*schema.Message, error) {
250				if len(state.UserInput) > 0 {
251					return []*schema.Message{schema.UserMessage(state.UserInput)}, nil
252				}
253				return in, nil
254			}))
255		if err != nil {
256			log.Fatal(err)
257		}
258	
259		err = g.AddLambdaNode(NodeKeyOutputConvert, compose.InvokableLambda(func(ctx context.Context, input []*schema.Message) (output string, err error) {
260			return input[len(input)-1].Content, nil
261		}))
262		if err != nil {
263			log.Fatal(err)
264		}
265	
266		// compose graph
267		err = g.AddEdge(compose.START, NodeKeyInputConvert)
268		if err != nil {
269			log.Fatal(err)
270		}
271		err = g.AddEdge(NodeKeyInputConvert, NodeKeyChatModel)
272		if err != nil {
273			log.Fatal(err)
274		}
275		err = g.AddBranch(NodeKeyChatModel, compose.NewGraphBranch(func(ctx context.Context, in *schema.Message) (endNode string, err error) {
276			if len(in.ToolCalls) > 0 {
277				return NodeKeyToolsNode, nil
278			}
279			return NodeKeyHuman, nil
280		}, map[string]bool{
281			NodeKeyToolsNode: true,
282			NodeKeyHuman:     true,
283		}))
284		if err != nil {
285			log.Fatal(err)
286		}
287		err = g.AddBranch(NodeKeyHuman, compose.NewGraphBranch(func(ctx context.Context, in []*schema.Message) (endNode string, err error) {
288			if in[len(in)-1].Role == schema.User {
289				return NodeKeyChatModel, nil
290			}
291			return NodeKeyOutputConvert, nil
292		}, map[string]bool{
293			NodeKeyChatModel:     true,
294			NodeKeyOutputConvert: true,
295		}))
296		err = g.AddEdge(NodeKeyToolsNode, NodeKeyChatModel)
297		if err != nil {
298			log.Fatal(err)
299		}
300		err = g.AddEdge(NodeKeyOutputConvert, compose.END)
301		if err != nil {
302			log.Fatal(err)
303		}
304	
305		runner, err := g.Compile(ctx, compose.WithCheckPointStore(newInMemoryStore()), compose.WithInterruptBeforeNodes([]string{NodeKeyHuman}))
306		if err != nil {
307			log.Fatal(err)
308		}
309	
310		return runner
311	}
